// TypeScript Map<> registry — zero external dependencies:
type ComponentType = 'spacekid' | 'spaceship' | 'environment' | 'dragProxy';
type CreateFn = (spec: ComponentSpec, scene: THREE.Scene) => ComponentInstance;
const registry = new Map<ComponentType, CreateFn>();
registry.set('spacekid', createSpacekidEntity);
registry.set('spaceship', createSpaceshipEntity);
// Factory dispatch:
function ComponentFactory(type: ComponentType, spec: ComponentSpec, scene: THREE.Scene): ComponentInstance {
  const createFn = registry.get(type);
  if (!createFn) throw new Error('Unknown component type: ' + type);
  return createFn(spec, scene);
}
// onEntityAdded hook for Three.js resource allocation:
const draggableEntities = { onAdd: (entity) => { entity.proxy = createProxy(entity.mesh); } };

import { World } from 'miniplex';

type PhotonicEntity = {
  mesh: THREE.Group;
  material?: THREE.MeshPhysicalMaterial;
  animationMixer?: THREE.AnimationMixer;
  dragProxy?: THREE.Mesh;
  proceduralSpec?: ProceduralCharacterSpec;
  spacekid?: true;
  spaceship?: true;
  draggable?: true;
}

const world = new World<PhotonicEntity>();

// Queries (defined once, reused — not per-frame):
const draggableEntities = world.with('spacekid', 'dragProxy');
const animatedEntities = world.with('spacekid', 'animationMixer');
const spaceshipEntities = world.with('spaceship', 'mesh');

// Spawn:
const spacekid = world.add({ mesh: gltfScene, animationMixer: mixer, dragProxy: proxy, spacekid: true, draggable: true });

// Systems (called each frame):
function animationSystem(delta: number) {
  for (const { animationMixer } of animatedEntities) {
    animationMixer.update(delta);
  }
}

// React to entity lifecycle:
world.with('dragProxy').onEntityAdded.subscribe(({ dragProxy, mesh }) => {
  dragControls.objects.push(dragProxy); // register proxy with DragControls
});

// Cleanup on remove (manual Three.js disposal required):
world.onEntityRemoved.subscribe(({ mesh, material }) => {
  mesh.traverse(child => { if (child instanceof THREE.Mesh) { child.geometry.dispose(); } });
  if (material) material.dispose();
});

// H-6 GestureClassifier using PointerEvents:
type GestureType = 'drag' | 'flick' | 'tap';

interface GestureState {
  startPos: THREE.Vector2;
  startTime: number;
  currentVelocity: THREE.Vector2;
  gestureType: GestureType | null;
}

// Setup on canvas:
renderer.domElement.addEventListener('pointerdown', onPointerDown, { passive: false });
renderer.domElement.addEventListener('pointermove', onPointerMove);
renderer.domElement.addEventListener('pointerup', onPointerUp);

// setPointerCapture for reliable tracking (MDN best practice):
function onPointerDown(e: PointerEvent) {
  renderer.domElement.setPointerCapture(e.pointerId);
  gestureState = { startPos: new THREE.Vector2(e.clientX, e.clientY), startTime: Date.now(), currentVelocity: new THREE.Vector2(), gestureType: null };
}

function onPointerMove(e: PointerEvent) {
  const elapsed = (Date.now() - gestureState.startTime) / 1000; // seconds
  const dx = e.clientX - gestureState.startPos.x;
  const dy = e.clientY - gestureState.startPos.y;
  gestureState.currentVelocity.set(dx / elapsed, dy / elapsed); // px/sec
}

function onPointerUp(e: PointerEvent) {
  renderer.domElement.releasePointerCapture(e.pointerId);
  const speed = gestureState.currentVelocity.length();
  const distance = new THREE.Vector2(e.clientX - gestureState.startPos.x, e.clientY - gestureState.startPos.y).length();
  if (distance < 10) { classifyGesture('tap'); }
  else if (speed > 600) { classifyGesture('flick'); }  // > 600 px/sec = flick
  else { classifyGesture('drag'); }
}

// PlacementZone evaluation (spatial proximity, no snap grid):
function findNearestZone(worldPos: THREE.Vector3, zones: PlacementZone[]): PlacementZone | null {
  return zones
    .filter(z => z.center.distanceTo(worldPos) <= z.radius)
    .sort((a, b) => a.center.distanceTo(worldPos) - b.center.distanceTo(worldPos))[0] ?? null;
}
